(%i1) assume (x > 0);
(%o1)                        [x > 0]


(%i2) integrate ((log (1 - t)) / t, t, 0, x);
Is x - 1 positive, negative or zero?



Is x - 1 positive, negative or zero?
li[4](1);


Is x - 1 positive, negative or zero?
li[5](1);


Is x - 1 positive, negative or zero?
li[2](1/2);


Is x - 1 positive, negative or zero?
li[2](%i);


Is x - 1 positive, negative or zero?
li[2](1+%i);


Is x - 1 positive, negative or zero?
li [2] (7);


