(%i4) rems : map(lambda([z], mod(x, z)), mods);
(%o4)                   [4, 568, 54, 624]


(%i5) solve_congruences(rems, mods);
(%o5)                     685124877004


(%i6) solve_congruences([1, 2], [3, n]);
